from __future__ import annotations
from typing import Dict, List, Optional, Tuple
import heapq

# Import Graph from context module.
from context.graph import Graph


def dijkstra(graph: Graph, source: int) -> Tuple[Dict[int, float], Dict[int, Optional[int]]]:
    """
    Dijkstra's single-source shortest paths.
    Returns `(dist, predecessor)` where `dist[v]` is the shortest distance from `source`.

    Time Complexity: O((V + E) * log(V)) using a binary heap, where V is number of vertices and E is number of edges.
    Space Complexity: O(V) for distances and predecessors, plus O(V) for the priority queue.
    """
    dist: Dict[int, float] = {v: float('inf') for v in graph.get_vertices()}
    pred: Dict[int, Optional[int]] = {v: None for v in graph.get_vertices()}

    if source not in dist:
        return {}, {}

    dist[source] = 0.0
    pq = [(0.0, source)]

    while pq:
        d, u = heapq.heappop(pq)

        if d > dist[u]:
            continue

        for v, weight in graph.get_neighbors(u):
            if weight < 0:
                # Dijkstra does not support negative weights
                continue

            alt = dist[u] + weight
            if alt < dist[v]:
                dist[v] = alt
                pred[v] = u
                heapq.heappush(pq, (alt, v))

    return dist, pred


def bellman_ford(graph: Graph, source: int) -> Tuple[Dict[int, float], Dict[int, Optional[int]], bool]:
    """
    Bellman-Ford single-source shortest paths.
    Returns `(dist, predecessor, has_negative_cycle)`.

    Time Complexity: O(V * E) where V is number of vertices and E is number of edges.
    Space Complexity: O(V) for distances and predecessors.
    """
    vertices = graph.get_vertices()
    dist: Dict[int, float] = {v: float('inf') for v in vertices}
    pred: Dict[int, Optional[int]] = {v: None for v in vertices}

    if source not in dist:
        return {}, {}, False

    dist[source] = 0.0

    # Relax all edges |V| - 1 times
    for _ in range(len(vertices) - 1):
        for u in vertices:
            if dist[u] != float('inf'):
                for v, weight in graph.get_neighbors(u):
                    if dist[u] + weight < dist[v]:
                        dist[v] = dist[u] + weight
                        pred[v] = u

    # Check for negative-weight cycles
    has_negative_cycle = False
    for u in vertices:
        if dist[u] != float('inf'):
            for v, weight in graph.get_neighbors(u):
                if dist[u] + weight < dist[v]:
                    has_negative_cycle = True
                    break
            if has_negative_cycle:
                break

    return dist, pred, has_negative_cycle


def floyd_warshall(graph: Graph) -> Tuple[Dict[int, Dict[int, float]], Dict[int, Dict[int, Optional[int]]]]:
    """
    Floyd-Warshall all-pairs shortest paths.
    Returns `(dist, next)` where `dist[i][j]` is shortest distance and `next` is used for paths.

    Time Complexity: O(V^3) where V is number of vertices.
    Space Complexity: O(V^2) for distances and next matrices.
    """
    vertices = graph.get_vertices()
    dist: Dict[int, Dict[int, float]] = {u: {v: float('inf') for v in vertices} for u in vertices}
    nxt: Dict[int, Dict[int, Optional[int]]] = {u: {v: None for v in vertices} for u in vertices}

    # Initialize distances and next array with direct edges
    for u in vertices:
        dist[u][u] = 0.0
        for v, weight in graph.get_neighbors(u):
            dist[u][v] = weight
            nxt[u][v] = v

    # Floyd-Warshall DP
    for k in vertices:
        for i in vertices:
            for j in vertices:
                if dist[i][k] != float('inf') and dist[k][j] != float('inf'):
                    alt = dist[i][k] + dist[k][j]
                    if alt < dist[i][j]:
                        dist[i][j] = alt
                        nxt[i][j] = nxt[i][k]

    return dist, nxt


class DisjointSet:
    def __init__(self, vertices: List[int]):
        self.parent = {v: v for v in vertices}
        self.rank = {v: 0 for v in vertices}

    def find(self, item: int) -> int:
        if self.parent[item] == item:
            return item
        self.parent[item] = self.find(self.parent[item])
        return self.parent[item]

    def union(self, x: int, y: int) -> bool:
        xroot = self.find(x)
        yroot = self.find(y)

        if xroot == yroot:
            return False

        if self.rank[xroot] < self.rank[yroot]:
            self.parent[xroot] = yroot
        elif self.rank[xroot] > self.rank[yroot]:
            self.parent[yroot] = xroot
        else:
            self.parent[yroot] = xroot
            self.rank[xroot] += 1

        return True


def kruskal_mst(graph: Graph) -> Tuple[List[Tuple[int, int, float]], float]:
    """
    Kruskal's minimum spanning tree for undirected graphs.
    Returns `(mst_edges, total_weight)`.

    Time Complexity: O(E * log(E)) to sort edges, plus O(E * alpha(V)) for disjoint set operations. Overall O(E * log(E)).
    Space Complexity: O(V) for disjoint set, O(E) for sorting and output edges.
