            total_weight += weight

            # Optimization: stop early if we have V-1 edges
            if len(mst_edges) == len(vertices) - 1:
                break

    return mst_edges, total_weight


def topological_sort(graph: Graph) -> List[int]:
    """
    Topological sort for directed acyclic graphs.
    Returns a list of vertices in topological order.
    Returns an empty list if the graph has a cycle.

    Time Complexity: O(V + E) where V is number of vertices and E is number of edges.
    Space Complexity: O(V) for recursion stack, visited sets, and result list.
    """
    if not graph.directed:
        # Undirected graphs cannot be topologically sorted
        return []

    vertices = graph.get_vertices()
    visited = set()
    temp_mark = set()
    result = []
    has_cycle = False

    def visit(n: int) -> None:
        nonlocal has_cycle
        if has_cycle:
            return
        if n in temp_mark:
            has_cycle = True
            return
        if n not in visited:
            temp_mark.add(n)
            for m, _ in graph.get_neighbors(n):
